public interface Swimmer {
    void swim(); // no body -- every method is implicitly abstract
}

public class Main {
    interface Swimmer {
        void swim();
    }

    static class Fish implements Swimmer {
        @Override
        public void swim() {
            System.out.println("The fish swims.");
        }
    }

    public static void main(String[] args) {
        Fish f = new Fish();
        f.swim();
    }
}

public class Main {
    interface Swimmer {
        void swim();
    }

    interface Flyer {
        void fly();
    }

    static class Duck implements Swimmer, Flyer {
        @Override
        public void swim() {
            System.out.println("The duck swims.");
        }

        @Override
        public void fly() {
            System.out.println("The duck flies.");
        }
    }

    public static void main(String[] args) {
        Duck d = new Duck();
        d.swim();
        d.fly();
    }
}

public class Main {
    interface Greeter {
        String getName();

        default void greet() {
            System.out.println("Hello, " + getName() + "!");
        }
    }

    static class Person implements Greeter {
        private String name;

        Person(String name) {
            this.name = name;
        }

        @Override
        public String getName() {
            return name;
        }
    }

    public static void main(String[] args) {
        Person p = new Person("Aman");
        p.greet();
    }
}

interface MathHelper {
    static int square(int x) {
        return x * x;
    }
}

// Called directly on the interface, like a static class method:
// MathHelper.square(5) -> 25

